-- FSI_DEMO_DB.BANKING.LOAN_PERFORMANCE

CREATE OR REPLACE TABLE FSI_DEMO_DB.BANKING.LOAN_PERFORMANCE (

    LOAN_ID VARCHAR(20) NOT NULL,
    APPLICATION_ID VARCHAR(20),
    CUSTOMER_ID VARCHAR(20),
    ORIGINATION_DATE DATE,
    MATURITY_DATE DATE,
    ORIGINAL_AMOUNT NUMBER(15,2),
    CURRENT_BALANCE NUMBER(15,2),
    MONTHLY_PAYMENT NUMBER(10,2),
    INTEREST_RATE NUMBER(5,4),
    PAYMENTS_MADE NUMBER(5,0),
    PAYMENTS_MISSED NUMBER(5,0),
    DAYS_PAST_DUE NUMBER(5,0),
    DELINQUENCY_STATUS VARCHAR(30),
    LAST_PAYMENT_DATE DATE,
    LAST_PAYMENT_AMOUNT NUMBER(10,2),
    TOTAL_PAID NUMBER(15,2),
    TOTAL_INTEREST_PAID NUMBER(15,2),
    DEFAULT_FLAG BOOLEAN DEFAULT FALSE,
    DEFAULT_DATE DATE,
    RECOVERY_AMOUNT NUMBER(15,2),
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (LOAN_ID)

);


